// Build NanoBanana prompts for each copy variant
const webhook = $node['Webhook: Image Ad Render'].json.body;
const swipe = ($node['Fetch Swipe Reference'].json || [])[0] || {};
const brand = ($node['Fetch Brand'].json || [])[0] || {};
const variants = webhook.variants || [];
const format = webhook.format || '1080x1080';

// Parse format to dimensions
const dims = {
  '1080x1080': { width: 1080, height: 1080 },
  '1080x1920': { width: 1080, height: 1920 },
  '1200x628': { width: 1200, height: 628 }
};
const { width, height } = dims[format] || dims['1080x1080'];

// Build a prompt for each variant
const items = variants.map((v, i) => {
  const basePrompt = swipe.recreation_prompt || 'Clean, modern ad layout';
  const brandColors = brand.brand_colors || {};

  const prompt = `Create an image ad with the following specifications:

VISUAL STYLE (from reference): ${basePrompt}

BRAND COLORS: Primary: ${brandColors.primary || '#000'}, Secondary: ${brandColors.secondary || '#fff'}, Accent: ${brandColors.accent || '#00ff88'}
BRAND VISUAL STYLE: ${brand.visual_style || 'Clean and professional'}

COPY TO INCLUDE:
HEADLINE: ${v.headline}
BODY: ${v.body_copy}
CTA BUTTON: ${v.cta}

Dimensions: ${width}x${height}
The text must be clearly readable. Use the brand colors. Match the layout style of the reference.`;

  return {
    json: {
      variant_index: i,
      copy_variant: v,
      prompt,
      reference_image_url: swipe.image_url || null,
      width,
      height,
      generation_id: webhook.generation_id
    }
  };
});

return items;

// Process NanoBanana response and prepare for Supabase insert
const prev = $input.first().json;
// NanoBanana response format may vary — adapt this parsing
const imageUrl = prev.output_url || prev.image_url || prev.images?.[0]?.url || `https://placeholder.com/generated-ad-${Date.now()}.png`;

return [{
  json: {
    generation_id: prev.generation_id,
    image_url: imageUrl,
    copy_variant: prev.copy_variant,
    image_prompt: prev.prompt,
    reference_image_url: prev.reference_image_url,
    performance_tag: 'untested',
    is_selected: false
  }
}];

// Build payload for creatives table insert
// Preserves the legacy image_ad_outputs row for backwards compatibility
const outputRow = $input.item.json;
const inputData = $('Webhook: Image Ad Render').first().json.body || {};
const processed = $('Process Result').first().json;

const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const week = Math.ceil((((now - startOfYear) / 86400000) + startOfYear.getDay() + 1) / 7);

// Figure out hook_number by how many items we've processed so far
// $itemIndex is available inside Code nodes that run per-item
const hookNumber = (typeof $itemIndex !== 'undefined' ? $itemIndex : 0) + 1;

// Pull the copy variant off the processed-result payload (not the Supabase insert response)
const variant = processed.copy_variant || outputRow.copy_variant || {};
const imageUrl = (Array.isArray(outputRow) ? outputRow[0]?.image_url : outputRow.image_url) || processed.image_url;

return {
  client_id: inputData.client_id || null,
  awareness_level: inputData.awareness_level || null,
  angle: inputData.angle || null,
  format: inputData.format || '1080x1080',
  week_number: week,
  year: now.getFullYear(),
  hook_number: hookNumber,
  body_number: 1,
  variant,
  image_url: imageUrl,
  legacy_output: Array.isArray(outputRow) ? outputRow[0] : outputRow
};

// Merge batch_id back into the creative context regardless of whether batch was found or created
const ctx = $('Prepare Creative Payload').item.json;
const incoming = $input.item.json;

let batchId;
if (Array.isArray(incoming) && incoming.length > 0) {
  // From Find Batch (IF true branch)
  batchId = incoming[0].id;
} else if (Array.isArray(incoming)) {
  // Create Batch returned array
  batchId = incoming[0]?.id;
} else if (incoming && incoming.id) {
  batchId = incoming.id;
} else if (incoming && Array.isArray(incoming) === false && incoming[0]?.id) {
  batchId = incoming[0].id;
}

return { ...ctx, batch_id: batchId };

// Merge concept_id back into the creative context regardless of branch
const ctx = $('Merge Batch ID').item.json;
const incoming = $input.item.json;

let conceptId;
if (Array.isArray(incoming) && incoming.length > 0) {
  conceptId = incoming[0].id;
} else if (incoming && incoming.id) {
  conceptId = incoming.id;
}

return { ...ctx, concept_id: conceptId };

// Collect all generated outputs and return as response
const items = $input.all();
const images = items.map(item => {
  const row = Array.isArray(item.json) ? item.json[0] : item.json;
  return {
    creative_id: row?.id || null,
    creative_name: row?.name || null,
    image_url: row?.image_url || null,
    hook_text: row?.hook_text || null,
    body_text: row?.body_text || null,
    cta_text: row?.cta_text || null,
    angle: row?.angle || null
  };
});

return [{ json: { success: true, images, count: images.length } }];
